using ModelContextProtocol.Server;

var builder = WebApplication.CreateBuilder(args);

builder.Services
    .AddMcpServer(options =>
    {
        options.ServerInfo = new() { Name = "MyMcpServer", Version = "1.0.0" };
    })
    .WithHttpTransport()
    .WithTools<MyTools>()
    .WithResources<MyResources>();

var app = builder.Build();

app.MapMcp();

app.Run();

// ── Tools ──────────────────────────────────────────────────────────────

[McpServerToolType]
public static class MyTools
{
    [McpServerTool(Name = "echo", Title = "Echo")]
    [System.ComponentModel.Description("Echoes the input message back to the caller.")]
    public static string Echo(string message) => $"Echo: {message}";

    [McpServerTool(Name = "add", Title = "Add Numbers")]
    [System.ComponentModel.Description("Adds two numbers and returns the sum.")]
    public static string Add(double a, double b) => $"Result: {a + b}";
}

// ── Resources ──────────────────────────────────────────────────────────

[McpServerResourceType]
public static class MyResources
{
    [McpServerResource(
        UriTemplate = "config://app",
        Name = "app-config",
        MimeType = "application/json")]
    [System.ComponentModel.Description("Returns application configuration data.")]
    public static string GetAppConfig() =>
        """
        {
          "featureFlags": { "darkMode": true, "betaAccess": false },
          "limits": { "maxUploadSizeMb": 50, "requestsPerMinute": 120 },
          "version": "1.0.0"
        }
        """;

    [McpServerResource(
        UriTemplate = "config://services/{serviceName}",
        Name = "service-config",
        MimeType = "application/json")]
    [System.ComponentModel.Description("Returns configuration for a named service.")]
    public static string GetServiceConfig(string serviceName) =>
        $$"""
        {
          "service": "{{serviceName}}",
          "endpoint": "https://api.example.com/{{serviceName}}",
          "timeout": 30,
          "retries": 3
        }
        """;
}

using ModelContextProtocol.Server;

var builder = WebApplication.CreateBuilder(args);

builder.Services
