        options.ServerInfo = new() { Name = "MyMcpServer", Version = "1.0.0" };
    })
    .WithHttpTransport()
    .WithTools<MyTools>()
    .WithResources<MyResources>();

var app = builder.Build();

app.MapMcp();

app.Run();

